import xml.etree.ElementTree as ET

def parse_xml_config(file_path):
    tree = ET.parse(file_path)
    root = tree.getroot()
    config_dict = {}

    for elem in root:
        if len(elem) > 0:
            inner_config = {}
            for subelem in elem:
                inner_config[subelem.tag] = subelem.text
            config_dict[elem.tag] = inner_config
        else:
            config_dict[elem.tag] = elem.text

    return config_dict